// Extract and structure message data
const message = $input.item.json.message;
const chatId = message.chat.id;
const userId = message.from.id;
const userName = message.from.first_name || 'Customer';
const userText = message.text || '';
const messageId = message.message_id;

// Store session data for downstream nodes
const sessionData = {
  chatId: chatId,
  userId: userId,
  userName: userName,
  messageText: userText.toLowerCase(), // Lowercase for intent matching
  originalText: userText, // Keep original for AI
  messageId: messageId,
  timestamp: new Date().toISOString()
};

return [sessionData];

// Intent Classification with Pattern Matching
const text = $input.item.json.messageText;
const originalText = $input.item.json.originalText;

let intent = 'general_inquiry';
let entities = {
  category: null,
  brand: null,
  priceRange: null
};

// Priority 1: Contact/Location queries (check first)
if (/where.*store|store.*locat|address|location|contact|phone|email|visit.*store|shop.*address/i.test(text)) {
  intent = 'contact_info';
  return [{...($input.item.json), intent, entities}];
}

// Priority 2: Greetings (only exact greetings)
if (/^(hi|hello|hey|good morning|good evening|good afternoon|start|greetings)$/i.test(text)) {
  intent = 'greeting';
  return [{...($input.item.json), intent, entities}];
}

// Priority 3: Thanks
if (/thank|thanks|appreciate|grateful/i.test(text)) {
  intent = 'thanks';
  return [{...($input.item.json), intent, entities}];
}

// Priority 4: Product categories
// CUSTOMIZE THESE PATTERNS FOR YOUR BUSINESS TYPE
const categories = [
  // Electronics/Tech Store Examples:
  { pattern: /(monitor|display|screen|tv)/i, category: 'monitors' },
  { pattern: /(laptop|notebook|computer)/i, category: 'laptops' },
  { pattern: /(phone|mobile|smartphone)/i, category: 'phones' },
  { pattern: /(headphone|earphone|earbuds|airpods)/i, category: 'audio' },

  // Fashion Store Examples:
  { pattern: /(shirt|tshirt|top|blouse)/i, category: 'clothing' },
  { pattern: /(jeans|pants|trousers)/i, category: 'bottomwear' },
  { pattern: /(dress|gown|saree)/i, category: 'ethnic' },
  { pattern: /(shoe|footwear|sneaker|sandal)/i, category: 'footwear' },
  { pattern: /(bag|purse|wallet)/i, category: 'accessories' },

  // Home/Furniture Examples:
  { pattern: /(sofa|couch|chair|seating)/i, category: 'furniture' },
  { pattern: /(bed|mattress|bedroom)/i, category: 'bedroom' },
  { pattern: /(table|desk|dining)/i, category: 'tables' },
  { pattern: /(decor|decoration|wall art)/i, category: 'decor' },

  // Beauty/Cosmetics Examples:
  { pattern: /(skincare|cream|serum|moisturizer)/i, category: 'skincare' },
  { pattern: /(makeup|lipstick|foundation)/i, category: 'makeup' },
  { pattern: /(perfume|fragrance|cologne)/i, category: 'fragrance' },

  // Food/Grocery Examples:
  { pattern: /(grocery|groceries|food)/i, category: 'groceries' },
  { pattern: /(vegetable|fruit|produce)/i, category: 'fresh' },
  { pattern: /(snack|chips|biscuit)/i, category: 'snacks' },

  // Add YOUR business-specific categories here
  // { pattern: /YOUR_KEYWORD/i, category: 'YOUR_CATEGORY' },
];

for (const cat of categories) {
  if (cat.pattern.test(text)) {
    intent = 'product_inquiry';
    entities.category = cat.category;
    break;
  }
}

// Priority 5: Order tracking
if (/track.*order|order.*status|where.*order|order.*id/i.test(text)) {
  intent = 'order_tracking';
}

// Priority 6: Price queries (if not already classified)
if (intent !== 'contact_info' && /price|cost|how much|budget|expensive|cheap|rate/i.test(text)) {
  intent = 'price_inquiry';
}

// Priority 7: Shipping/Delivery
if (/shipping|delivery|courier|dispatch|arrive|reach/i.test(text)) {
  intent = 'shipping_inquiry';
}

// Priority 8: Return/Refund
if (/return|refund|exchange|replace|cancel/i.test(text)) {
  intent = 'return_request';
}

// Priority 9: Support queries
if (/help|support|problem|issue|complaint|not working/i.test(text)) {
  intent = 'support_request';
}

return [{...($input.item.json), intent, entities}];

// Generate Product Catalog Response
const category = $input.item.json.entities.category;
const userName = $input.item.json.userName;

let response = '';

// YOUR_AWS_SECRET_KEY_HERE
// CUSTOMIZE WITH YOUR ACTUAL PRODUCTS
// YOUR_AWS_SECRET_KEY_HERE
// The examples below show different business types
// Replace with YOUR products, prices, and categories

// EXAMPLE 1: Electronics Store
if (category === 'monitors') {
  response = `Great choice, ${userName}! Check out our *MONITORS*:

`;
  response += `1. *24" Full HD Monitor*
   💰 ₹8,999
   ✅ In Stock
   🔗 https://yourstore.com/monitors

`;
  response += `2. *27" 4K Professional Display*
   💰 ₹22,999
   🎉 20% OFF!
   🔗 https://yourstore.com/monitors

`;
}

// EXAMPLE 2: Fashion Store
else if (category === 'clothing') {
  response = `Hi ${userName}! Here are our trending *CLOTHING* items:

`;
  response += `👕 *Men's Cotton T-Shirts*
   💰 Starting at ₹399
   🔗 https://yourstore.com/mens-tshirts

`;
  response += `👗 *Women's Summer Dresses*
   💰 ₹1,299 - ₹2,999
   🎉 Buy 2 Get 10% OFF
   🔗 https://yourstore.com/dresses

`;
}

// EXAMPLE 3: Home Decor Store
else if (category === 'furniture') {
  response = `Wonderful choice, ${userName}! Our *FURNITURE* collection:

`;
  response += `🛋️ *3-Seater Sofa Set*
   💰 ₹24,999
   🚚 Free Delivery
   🔗 https://yourstore.com/sofas

`;
  response += `🪑 *Dining Table (6-Seater)*
   💰 ₹15,999
   ✅ Solid Wood
   🔗 https://yourstore.com/dining

`;
}

// EXAMPLE 4: Beauty & Cosmetics
else if (category === 'skincare') {
  response = `Great selection, ${userName}! Our *SKINCARE* products:

`;
  response += `✨ *Vitamin C Face Serum*
   💰 ₹599
   🌿 100% Natural
   🔗 https://yourstore.com/skincare

`;
  response += `💆 *Anti-Aging Night Cream*
   💰 ₹899
   ⭐ Bestseller!
   🔗 https://yourstore.com/skincare

`;
}

// EXAMPLE 5: Food & Grocery
else if (category === 'groceries') {
  response = `Perfect, ${userName}! Check our *GROCERIES*:

`;
  response += `🌾 *Organic Rice (5kg)*
   💰 ₹450
   🌱 Chemical-free
   🔗 https://yourstore.com/groceries

`;
  response += `🫘 *Mixed Nuts Pack (500g)*
   💰 ₹299
   💪 High Protein
   🔗 https://yourstore.com/dry-fruits

`;
}

// Default: Show all categories
else {
  response = `Hi ${userName}! Browse our categories:

`;
  response += `📱 [Category 1]
`;
  response += `👕 [Category 2]
`;
  response += `🏠 [Category 3]
`;
  response += `💄 [Category 4]

`;
  response += `🌐 Visit: https://yourstore.com/`;
}

// Add universal call-to-action
response += `

✨ Special Offer: [Your Current Promotion]`;
response += `
📞 Questions? Call: +91 XXXXXXXXXX`;
response += `
💬 Or just reply here!`;

return [{
  chatId: $input.item.json.chatId,
  response: response,
  parseMode: 'Markdown'
}];

// Generate Contact Information Response
const userName = $input.item.json.userName;

// CUSTOMIZE THIS WITH YOUR COMPANY DETAILS
const response = `📍 *Your Company Name - Contact Details*

🏢 *Address:*
Your Street Address
City, State - PIN Code

📞 *Phone:*
+91 XXXXXXXXXX (Main)
+91 XXXXXXXXXX (Sales)
+91 XXXXXXXXXX (Support)

📧 *Email:*\user@example.com\user@example.com

🌐 *Website:*
https://yourcompany.com/

⏰ *Store Hours:*
Mon-Sat: 10 AM - 8 PM
Sunday: 11 AM - 6 PM

Feel free to visit us, ${userName}! 😊`;

return [{
  chatId: $input.item.json.chatId,
  response: response,
  parseMode: 'Markdown'
}];

// Format AI response for WhatsApp
const aiResponse = $input.first().json.output;
const chatId = $input.first().json.chatId;

return [{
  chatId: chatId,
  response: aiResponse,
  parseMode: 'Markdown'
}];
